parameters.jsCode:
// Filter out alumni who already registered for the current event
const response = $input.first().json;
const contacts = response.results || [];
const eventId = $('Set Campaign Config').first().json.event_id;

if (contacts.length === 0) {
  return [{ json: { empty: true, message: 'No past attendees found in HubSpot' } }];
}

const eligible = contacts.filter(contact => {
  const props = contact.properties || {};
  const pastEvents = (props.event_registration || '').toLowerCase();

  // Skip if already registered for current event
  if (pastEvents.includes(eventId.toLowerCase())) return false;

  // Must have an email
  if (!props.email) return false;

  return true;
});

if (eligible.length === 0) {
  return [{ json: { empty: true, message: 'All past attendees already registered for ' + eventId } }];
}

// Normalize HubSpot contact data for downstream nodes
return eligible.map(contact => {
  const p = contact.properties || {};
  return {
    json: {
      hubspot_id: contact.id,
      email: p.email,
      first_name: p.firstname || '',
      last_name: p.lastname || '',
      company: p.company || '',
      role: p.jobtitle || '',
      industry: p.industry || '',
      location: [p.city, p.country].filter(Boolean).join(', '),
      events_attended: p.event_registration || '',
      lifecycle_stage: p.lifecyclestage || '',
      lead_status: p.hs_lead_status || '',
      deals_count: parseInt(p.num_associated_deals || '0', 10)
    }
  };
});

// Segment alumni by engagement level (using HubSpot data)
const alumni = $input.all();

return alumni.map(a => {
  const d = a.json;

  // Count past events from the event_registration property (comma-separated)
  const eventsAttended = (d.events_attended || '').split(',').map(s => s.trim()).filter(Boolean);
  const eventsCount = eventsAttended.length;

  // Segment by attendance history + deal activity
  let segment = 'one-timer';
  if (eventsCount >= 3 || d.deals_count >= 2) segment = 'champion';
  else if (eventsCount >= 2) segment = 'returning';

  return {
    json: {
      ...d,
      segment,
      events_count: eventsCount,
      past_events: eventsAttended,
      event_id: $('Set Campaign Config').first().json.event_id,
      event_name: $('Set Campaign Config').first().json.event_name,
      event_date: $('Set Campaign Config').first().json.event_date,
      reg_url: $('Set Campaign Config').first().json.reg_url
    }
  };
});

// Log alumni outreach for tracking
const alumni = $('Segment Alumni by Engagement').item.json;
return [{
  json: {
    hubspot_id: alumni.hubspot_id || '',
    email: alumni.email,
    segment: alumni.segment,
    events_count: alumni.events_count,
    event_id: alumni.event_id,
    sent_at: new Date().toISOString(),
    status: 'sent'
  }
}];

